/**
 * Generated by `createservice miniapp.ChangeOIDCClientService`
 */

const { generateGqlQueries } = require('@open-condo/codegen/generate.gql')
const { generateGQLTestUtils } = require('@open-condo/codegen/generate.test.utils')
const { GQLErrorCode: { BAD_USER_INPUT } } = require('@open-condo/keystone/errors')
const { makeClient } = require('@open-condo/keystone/test.utils')
const {
    expectToThrowAccessDeniedErrorToResult,
    expectToThrowAuthenticationErrorToResult,
    expectToThrowGQLError,
} = require('@open-condo/keystone/test.utils')

const { OIDC_CLIENT_NOT_FOUND } = require('@dev-portal-api/domains/miniapp/constants/errors')
const { DEV_ENVIRONMENT } = require('@dev-portal-api/domains/miniapp/constants/publishing')
const {
    changeOIDCClientByTestClient,
    createTestB2CApp,
    createTestB2BApp,
    createOIDCClientByTestClient,
    publishB2CAppByTestClient,
    B2CApp,
} = require('@dev-portal-api/domains/miniapp/utils/testSchema')
const {
    makeLoggedInAdminClient,
    makeLoggedInSupportClient,
    makeRegisteredAndLoggedInUser,
    makeLoggedInCondoAdminClient,
} = require('@dev-portal-api/domains/user/utils/testSchema')

const CondoB2CApp = generateGQLTestUtils(generateGqlQueries('B2CApp', '{ id oidcClient { id } }'))

describe('ChangeOIDCClientService', () => {
    let admin
    let support
    let anonymous
    let condoAdmin

    beforeAll(async () => {
        admin = await makeLoggedInAdminClient()
        support = await makeLoggedInSupportClient()
        anonymous = await makeClient()
        condoAdmin = await makeLoggedInCondoAdminClient()
    })

    describe('Access tests', () => {
        test('Anonymous cannot call changeOIDCClient', async () => {
            const user = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2CApp(user)
            const [client] = await createOIDCClientByTestClient(user, app)

            await expectToThrowAuthenticationErrorToResult(async () => {
                await changeOIDCClientByTestClient(anonymous, app, client.id)
            })
        })

        test('User cannot change OIDC client for another user\'s app', async () => {
            const owner = await makeRegisteredAndLoggedInUser()
            const other = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2CApp(owner)
            const [client] = await createOIDCClientByTestClient(owner, app)

            await expectToThrowAccessDeniedErrorToResult(async () => {
                await changeOIDCClientByTestClient(other, app, client.id)
            })
        })

        test('User can change OIDC client for their own B2CApp', async () => {
            const user = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2CApp(user)
            const [client] = await createOIDCClientByTestClient(user, app)

            const [result] = await changeOIDCClientByTestClient(user, app, client.id)
            expect(result).toHaveProperty('id', client.id)
        })

        test('User can change OIDC client for their own B2BApp', async () => {
            const user = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2BApp(user)
            const [client] = await createOIDCClientByTestClient(user, app)

            const [result] = await changeOIDCClientByTestClient(user, app, client.id)
            expect(result).toHaveProperty('id', client.id)
        })

        test('Admin can change OIDC client for any app', async () => {
            const user = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2CApp(user)
            const [client] = await createOIDCClientByTestClient(user, app)

            const [result] = await changeOIDCClientByTestClient(admin, app, client.id)
            expect(result).toHaveProperty('id', client.id)
        })

        test('Support can change OIDC client for any app', async () => {
            const user = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2CApp(user)
            const [client] = await createOIDCClientByTestClient(user, app)

            const [result] = await changeOIDCClientByTestClient(support, app, client.id)
            expect(result).toHaveProperty('id', client.id)
        })
    })

    describe('Logic tests', () => {
        test('Throws OIDC_CLIENT_NOT_FOUND when clientId belongs to another user\'s app', async () => {
            const user = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2CApp(user)

            const otherUser = await makeRegisteredAndLoggedInUser()
            const [otherApp] = await createTestB2CApp(otherUser)
            const [otherClient] = await createOIDCClientByTestClient(otherUser, otherApp)

            await expectToThrowGQLError(async () => {
                await changeOIDCClientByTestClient(user, app, otherClient.id)
            }, {
                code: BAD_USER_INPUT,
                type: OIDC_CLIENT_NOT_FOUND,
            }, 'result')
        })

        test('Sets oidcClientId on local app and returns the client', async () => {
            const user = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2CApp(user)
            const [client] = await createOIDCClientByTestClient(user, app)

            const [result] = await changeOIDCClientByTestClient(user, app, client.id)
            expect(result).toHaveProperty('id', client.id)
            expect(result).toHaveProperty('clientId')
            expect(result).toHaveProperty('redirectUri')
            expect(result).toHaveProperty('isEnabled')

            const refreshedApp = await B2CApp.getOne(user, { id: app.id })
            expect(refreshedApp).toHaveProperty('developmentOidcClientId', client.id)
        })

        test('Can switch to a different OIDC client', async () => {
            const user = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2CApp(user)
            const [firstClient] = await createOIDCClientByTestClient(user, app)

            const [anotherApp] = await createTestB2CApp(user)
            const [secondClient] = await createOIDCClientByTestClient(user, anotherApp)

            await changeOIDCClientByTestClient(user, app, firstClient.id)
            const [result] = await changeOIDCClientByTestClient(user, app, secondClient.id)
            expect(result).toHaveProperty('id', secondClient.id)

            const refreshedApp = await B2CApp.getOne(user, { id: app.id })
            expect(refreshedApp).toHaveProperty('developmentOidcClientId', secondClient.id)
        })

        test('Also links condoApp.oidcClient when app is published', async () => {
            const user = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2CApp(user)
            const [client] = await createOIDCClientByTestClient(user, app)

            await publishB2CAppByTestClient(user, app, { info: true }, DEV_ENVIRONMENT)
            const refreshedApp = await B2CApp.getOne(user, { id: app.id })

            await changeOIDCClientByTestClient(user, app, client.id)

            const condoApp = await CondoB2CApp.getOne(condoAdmin, { id: refreshedApp.developmentExportId })
            expect(condoApp).toHaveProperty(['oidcClient', 'id'], client.id)
        })

        test('Does not fail when app is not published (no condoApp)', async () => {
            const user = await makeRegisteredAndLoggedInUser()
            const [app] = await createTestB2CApp(user)
            const [client] = await createOIDCClientByTestClient(user, app)

            const [result] = await changeOIDCClientByTestClient(user, app, client.id)
            expect(result).toHaveProperty('id', client.id)
        })
    })
})